actions.script:
def sd = ec.service.getServiceDefinition(serviceName)
// Moqui verb convention mirrors authz-action derivation: these are reads,
// everything else (create/update/delete/store/send/...) is a write.
def READ_VERBS = ['get','find','search','view','list','check','calculate',
                  'validate','count','export'] as Set
// Implicit entity-auto CRUD (create#/get#/update#/delete#<Entity>) has NO
// ServiceDefinition, so fall back to the verb prefix of the service name —
// otherwise every entity-auto call is misclassified as a write.
def verb = sd?.verb ?: (serviceName?.contains('#') ? serviceName.substring(0, serviceName.indexOf('#')) : '')
verbClass = READ_VERBS.contains(verb) ? 'read' : 'write'

def pinned = new LinkedHashMap(parameters ?: [:])
ownerPartyId = cfg?.ownerPartyId
agentPartyId = cfg?.agentPartyId
// Does the target accept an ownerPartyId? Defined services: read the in-params.
// Entity-auto CRUD: inspect the entity's fields so tenant-pinning still applies.
def acceptsOwner = false
if (sd != null) {
    acceptsOwner = sd.getInParameterNames()?.contains('ownerPartyId') ?: false
} else if (serviceName?.contains('#')) {
    try {
        String entName = serviceName.substring(serviceName.indexOf('#') + 1)
        def ed = ec.entity.getEntityDefinition(entName)
        acceptsOwner = ed?.getAllFieldNames()?.contains('ownerPartyId') ?: false
    } catch (ignored) { }
}
tenantViolation = false
if (ownerPartyId && acceptsOwner) {
    if (pinned.ownerPartyId && (pinned.ownerPartyId as String) != (ownerPartyId as String))
        tenantViolation = true
    pinned.ownerPartyId = ownerPartyId   // pin to the agent's own tenant
}
parameters = pinned

// New agents are created with explicit safe defaults (readOnly/approve) by
// AdkServices.update#AgentConfig. A null here therefore means a legacy row
// created before governance existed → treat as unrestricted so existing
// agents (e.g. the CI Monitor) keep working until an admin scopes them.
def toolMode    = cfg?.toolMode ?: 'full'
def writePolicy = cfg?.writePolicy ?: 'allow'
decision = 'allowed'
message  = null

if (tenantViolation) {
    decision = 'blocked'
    message  = "Cross-tenant access denied: agent may only act on its own company."
} else if (cfg == null) {
    // No agent config resolved (e.g. MCP called outside an ADK agent, or
    // configId not propagated). Allow but flag — preserves legacy behaviour.
    decision = 'allowed'
    message  = 'ungoverned: no agent config resolved'
} else {
    if (toolMode == 'readOnly' && verbClass == 'write') {
        decision = 'blocked'
        message  = "This agent is read-only and may not run '${serviceName}'."
    } else if (toolMode == 'scoped') {
        def globs = ((cfg.serviceAllowlist ?: '') as String).split(/[,\s]+/).findAll { it }
        def ok = globs.any { g ->
            def rx = '^' + java.util.regex.Pattern.quote(g).replace('\\*', '\\E.*\\Q') + '$'
            serviceName ==~ rx
        }
        if (!ok) {
            decision = 'blocked'
            message  = "'${serviceName}' is not in this agent's allowed-service list."
        }
    }
    if (decision == 'allowed') {
        def hasCustomLlm = false
        if (cfg?.apiKey) hasCustomLlm = true
        if (!hasCustomLlm && ownerPartyId) {
            def lc = ec.entity.find('growerp.general.LlmConfig')
                .condition('ownerPartyId', ownerPartyId)
                .condition('llmProvider', 'gemini').one()
            if (lc?.apiKey) hasCustomLlm = true
        }
        if (!hasCustomLlm && ownerPartyId) {
            def ss = ec.entity.find('growerp.general.SystemSettings').condition('ownerPartyId', ownerPartyId).one()
            if (ss?.llmSystemTokenLimit != null && ss.llmSystemTokenLimit > 0) {
                def cal = Calendar.getInstance()
                cal.set(Calendar.DAY_OF_MONTH, 1)
                cal.set(Calendar.HOUR_OF_DAY, 0)
                cal.set(Calendar.MINUTE, 0)
                cal.set(Calendar.SECOND, 0)
                def startOfMonth = new java.sql.Timestamp(cal.getTimeInMillis())

                def iter = ec.entity.find('moqui.adk.AdkActionLog')
                    .condition('ownerPartyId', ownerPartyId)
                    .condition('actionTime', org.moqui.entity.EntityCondition.GREATER_THAN_EQUAL_TO, startOfMonth)
                    .selectField('tokensTotal').iterator()
                long totalUsed = 0
                while (iter.hasNext()) {
                    def r = iter.next()
                    totalUsed += (r.tokensTotal ?: 0)
                }
                iter.close()

                if (totalUsed >= ss.llmSystemTokenLimit) {
                    decision = 'blocked'
                    message = "System LLM token limit exceeded for this month (${totalUsed} >= ${ss.llmSystemTokenLimit}). Please add your own API Key."
                }
            }
        }
    }
    if (decision == 'allowed' && verbClass == 'write') {
        if (writePolicy == 'block') {
            decision = 'blocked'
            message  = "Write actions are disabled for this agent."
        } else if (writePolicy == 'approve') {
            decision = 'pending'
            message  = "Action queued for human approval before it runs."
        }
    }
}
argsJson = groovy.json.JsonOutput.toJson(pinned)

def args = appr.argsJson ? new groovy.json.JsonSlurper().parseText(appr.argsJson as String) : [:]
def res
try {
    res = ec.service.sync().name(appr.serviceName as String).parameters(args).call()
    resultSummary = groovy.json.JsonOutput.toJson(res).take(2000)
    status = 'approved'
} catch (Exception e) {
    resultSummary = "Execution failed: ${e.message}"
    status = 'approved'   // decision stands; record the failure
}
